const data = $input.first().json;

// Meta API 응답 평탄화
const raw = {};
if (data.data && Array.isArray(data.data)) {
  for (const item of data.data) {
    const val = item.values?.[0]?.value ?? item.value ?? 0;
    raw[item.name] = val;
  }
}

const reach   = Number(raw.reach ?? 0);
const saved   = Number(raw.saved ?? 0);
const plays   = Number(raw.plays ?? 0);
const avgMs   = Number(raw.ig_reels_avg_watch_time ?? 0);
const avgSec  = Math.round(avgMs / 1000 * 10) / 10;

const saveRate = reach > 0 ? ((saved / reach) * 100).toFixed(1) + '%' : 'N/A';

// 구매 의도 신호 평가
let signal = '낮음';
if (saved >= 20 || (reach > 0 && saved / reach >= 0.03)) signal = '높음 🔥';
else if (saved >= 5 || (reach > 0 && saved / reach >= 0.01)) signal = '중간 👀';

return [{
  json: {
    reach,
    plays,
    avg_watch_sec: avgSec,
    saved,
    shares:   Number(raw.shares ?? 0),
    comments: Number(raw.comments ?? 0),
    likes:    Number(raw.likes ?? 0),
    total_interactions: Number(raw.total_interactions ?? 0),
    save_rate: saveRate,
    purchase_intent_signal: signal,
    summary: `도달 ${reach.toLocaleString()} · 저장 ${saved} (${saveRate}) · 재생 ${plays.toLocaleString()} · 평균시청 ${avgSec}초 · 구매의도신호 ${signal}`
  }
}];
